import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Allocate memory dynamically based on user input length
        byte[] buffer = new byte[userInput.length()];

        // Copy user input into the buffer without overflowing
        for (int i = 0; i < userInput.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = (byte) userInput.charAt(i);
            } else {
                // Handle buffer overflow by breaking out of the loop or resizing the buffer
                System.out.println("Buffer overflow detected");
                break;
            }
        }

        System.out.println("Buffer overflow avoided");
    }
}

